from flask import Flask, redirect, request, session, jsonify, url_for
import secrets
import jwt
import requests
from functools import wraps
from datetime import datetime, timedelta

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

OIDC_CONFIG = {
    'client_id': 'your-client-id',
    'client_secret': 'your-client-secret',
    'authorization_endpoint': 'https://your-idp.com/authorize',
    'token_endpoint': 'https://your-idp.com/token',
    'jwks_uri': 'https://your-idp.com/.well-known/jwks.json',
    'redirect_uri': 'http://localhost:5000/callback',
    'scope': 'openid profile email'
}

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

@app.route('/')
@login_required
def index():
    return jsonify({
        'message': 'Admin Dashboard',
        'user': session.get('user')
    })

@app.route('/login')
def login():
    nonce = secrets.token_urlsafe(32)
    state = secrets.token_urlsafe(32)
    
    session['nonce'] = nonce
    session['state'] = state
    
    auth_params = {
        'client_id': OIDC_CONFIG['client_id'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'scope': OIDC_CONFIG['scope'],
        'response_type': 'code',
        'state': state,
        'nonce': nonce
    }
    
    auth_url = OIDC_CONFIG['authorization_endpoint'] + '?' + '&'.join(
        f"{k}={v}" for k, v in auth_params.items()
    )
    
    return redirect(auth_url)

@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return jsonify({'error': error}), 400
    
    state = request.args.get('state')
    if state != session.get('state'):
        return jsonify({'error': 'Invalid state parameter'}), 400
    
    code = request.args.get('code')
    if not code:
        return jsonify({'error': 'No authorization code received'}), 400
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret']
    }
    
    token_response = requests.post(
        OIDC_CONFIG['token_endpoint'],
        data=token_data
    )
    
    if token_response.status_code != 200:
        return jsonify({'error': 'Token exchange failed'}), 400
    
    tokens = token_response.json()
    id_token = tokens.get('id_token')
    
    try:
        decoded_token = jwt.decode(
            id_token,
            options={"verify_signature": False}
        )
        
        if decoded_token.get('nonce') != session.get('nonce'):
            return jsonify({'error': 'Invalid nonce'}), 400
        
        if decoded_token.get('aud') != OIDC_CONFIG['client_id']:
            return jsonify({'error': 'Invalid audience'}), 400
        
        if decoded_token.get('exp', 0) < datetime.utcnow().timestamp():
            return jsonify({'error': 'Token expired'}), 400
        
        session['user'] = {
            'sub': decoded_token.get('sub'),
            'email': decoded_token.get('email'),
            'name': decoded_token.get('name')
        }
        session['id_token'] = id_token
        
        session.pop('nonce', None)
        session.pop('state', None)
        
        return redirect(url_for('index'))
        
    except jwt.InvalidTokenError as e:
        return jsonify({'error': f'Invalid token: {str(e)}'}), 400

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True, port=5000)